patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index de3b981a4fe3..298c55c97e1d 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7326,7 +7326,12 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // Check if the instruction is in the VPlan
+      if (SeenInstrs.contains(&I))
+        return false;
+      // Check if the instruction should be ignored in cost computation
+      // Don't check SkipCostComputation as it's populated during precomputeCosts
+      return !CostCtx.CM.ValuesToIgnore.contains(&I) && !CostCtx.CM.VecValuesToIgnore.contains(&I);
     });
   });
 }

